-- ============================================
-- Qualitative Kurzanleitungen für alle Übungen
-- ============================================

UPDATE exercise_library SET howto = 'Aufrecht stehen, Arme seitlich. Gleichzeitig Arme über Kopf klatschen und Beine spreizen. Zurück in Ausgangsposition. Tempo gleichmäßig, 30–60 Sekunden.' WHERE name = 'Jumping Jacks' AND howto IS NULL;

UPDATE exercise_library SET howto = 'Arme gestreckt auf Schulterhöhe. Kleine Kreise vorwärts (15 s), dann rückwärts (15 s). Amplitude langsam vergrößern. Schultern bewusst nach unten ziehen.' WHERE name = 'Arm Circles' AND howto IS NULL;

UPDATE exercise_library SET howto = 'Arme locker seitlich schwingen: vorwärts über Kopf, dann rückwärts hinter den Körper. Dynamisch, nicht ruckartig. Schultern aktiv bewegen.' WHERE name = 'Arm Swings' AND howto IS NULL;

UPDATE exercise_library SET howto = 'Stehend, Beine hüftbreit. Abwechselnd Knie explosiv zur Brust ziehen. Arme gegengleich mitführen. Auf Vorfuß landen. Oberkörper aufrecht.' WHERE name = 'High Knees' AND howto IS NULL;

UPDATE exercise_library SET howto = 'Seitlich an Wand abstützen. Bein gestreckt vor/zurück schwingen, Amplitude steigern. 10× pro Seite frontal, 10× lateral (seitlich).' WHERE name = 'Leg Swings' AND howto IS NULL;

UPDATE exercise_library SET howto = 'Langsame Kreisbewegungen der Schultern. 10× vorwärts, 10× rückwärts. Schulterblätter bewusst zusammenziehen und lösen.' WHERE name = 'Schulterkreisen' AND howto IS NULL;

UPDATE exercise_library SET howto = 'Vierfüßlerstand. Einatmen: Brust senken, Blick nach oben (Cow). Ausatmen: Rücken maximal runden, Kinn zur Brust (Cat). Langsam, 8–10 Wiederholungen.' WHERE name = 'Cat-Cow Stretch' AND howto IS NULL;

UPDATE exercise_library SET howto = 'Seil locker in den Händen halten, Handgelenke rotieren. Auf Vorfuß springen, Knie leicht gebeugt. Seil schlägt unter den Füßen durch. Tempo gleichmäßig steigern.' WHERE name = 'Seilspringen' AND howto IS NULL;

UPDATE exercise_library SET howto = 'Schulterbreiter Griff, Hände unter Schultern. Körper bildet gerade Linie von Kopf bis Fuß. Arme beugen bis Brust fast den Boden berührt. Explosiv hochdrücken. Core anspannen.' WHERE name = 'Liegestütze klassisch' AND howto IS NULL;

UPDATE exercise_library SET howto = 'Hände eng zusammen unter der Brust (Daumen und Zeigefinger können sich berühren). Ellbogen bleiben am Körper. Langsam senken, kraftvoll drücken. Trizeps-Fokus.' WHERE name = 'Liegestütze eng' AND howto IS NULL;

UPDATE exercise_library SET howto = 'Aus dem Liegestütz Hüfte hoch in umgekehrtes V (Pike-Position). Kopf Richtung Boden senken, Ellbogen beugen. Zurückdrücken. Schulter-Fokus.' WHERE name = 'Pike Push-Ups' AND howto IS NULL;

UPDATE exercise_library SET howto = 'Hände auf Stuhlkante, Finger nach vorn. Beine gestreckt oder gebeugt. Körper senken bis Oberarme parallel zum Boden. Hochdrücken. Schultern weg von den Ohren.' WHERE name = 'Dips (Stuhl)' AND howto IS NULL;

UPDATE exercise_library SET howto = 'Füße auf erhöhter Fläche (Bank, Stufe). Hände schulterbreit am Boden. Liegestütz ausführen. Mehr Belastung auf oberer Brust und Schultern.' WHERE name = 'Decline Push-Ups' AND howto IS NULL;

UPDATE exercise_library SET howto = 'Daumen und Zeigefinger beider Hände bilden eine Raute auf dem Boden. Ellbogen eng am Körper. Langsam senken, explosiv drücken. Intensiver Trizeps-Reiz.' WHERE name = 'Diamond Push-Ups' AND howto IS NULL;

UPDATE exercise_library SET howto = 'Flachbank, Kurzhantel in jeder Hand. Schulterblätter zusammenziehen. Hanteln auf Brusthöhe senken (2 s), explosiv hochdrücken (1 s). Oberarme 45° zum Körper.' WHERE name = 'KH Bankdrücken' AND howto IS NULL;

UPDATE exercise_library SET howto = 'Sitzend oder stehend, Kurzhanteln auf Schulterhöhe. Über Kopf drücken bis Arme fast gestreckt. Kontrolliert senken. Core anspannen, kein Hohlkreuz.' WHERE name = 'KH Schulterdrücken' AND howto IS NULL;

UPDATE exercise_library SET howto = 'An Tischkante, Stange oder TRX greifen. Körper in Schräglage, Füße am Boden. Brust zur Stange/Kante ziehen, Schulterblätter zusammen. Kontrolliert zurück.' WHERE name = 'Bodyweight Rows' AND howto IS NULL;

UPDATE exercise_library SET howto = 'Bauchlage, Arme seitlich ausgestreckt. Arme in Schneeengel-Bewegung über Kopf und zurück führen. Schulterblätter aktiv zusammenziehen. Stirn bleibt am Boden.' WHERE name = 'Reverse Snow Angels' AND howto IS NULL;

UPDATE exercise_library SET howto = 'Bauchlage, Arme nach vorn gestreckt. Gleichzeitig Arme und Beine vom Boden heben. 3–5 Sekunden halten. Rücken anspannen, nicht ins Hohlkreuz fallen.' WHERE name = 'Superman Hold' AND howto IS NULL;

UPDATE exercise_library SET howto = 'An offenem Türrahmen festhalten, Füße nah an der Tür. Zurücklehnen, Arme gestreckt. Körper zum Rahmen ziehen, Schulterblätter zusammen. Kontrolliert zurück.' WHERE name = 'Türziehen' AND howto IS NULL;

UPDATE exercise_library SET howto = 'Stehend, Kurzhantel in jeder Hand. Arme hängen seitlich, Handflächen zum Körper. Unterarme beugen, oben kurz anspannen (Squeeze). Langsam senken (2 s).' WHERE name = 'Bicep Curls' AND howto IS NULL;

UPDATE exercise_library SET howto = 'Wie Bizeps-Curls, aber Handflächen zeigen zueinander (neutraler Griff). Daumen oben. Trainiert Brachioradialis und Bizeps. Kontrollierte Bewegung.' WHERE name = 'Hammer Curls' AND howto IS NULL;

UPDATE exercise_library SET howto = 'Knie und Hand auf Bank, andere Hand hält Kurzhantel. Hantel zum Hüftknochen ziehen, Ellbogen eng am Körper. Schulterblatt zusammenziehen, 1 s halten. Langsam senken.' WHERE name = 'KH Rudern einarmig' AND howto IS NULL;

UPDATE exercise_library SET howto = 'Band auf Schulterhöhe halten, Arme gestreckt. Arme auseinanderziehen bis Band die Brust berührt. Schulterblätter zusammenpressen. Kontrolliert zurück. 15–20 Wdh.' WHERE name = 'Band Pull-Aparts' AND howto IS NULL;

UPDATE exercise_library SET howto = 'Füße schulterbreit, Zehenspitzen leicht nach außen. Hüfte zurück und tief senken, mindestens parallel. Knie über Zehenspitzen. Brust hoch, Rücken gerade. Explosiv aufstehen.' WHERE name = 'Kniebeugen' AND howto IS NULL;

UPDATE exercise_library SET howto = 'Großer Schritt nach vorn, hinteres Knie fast zum Boden. Oberkörper aufrecht, Knie über Knöchel. Zurück in Ausgangsposition. Seiten abwechseln.' WHERE name = 'Ausfallschritte' AND howto IS NULL;

UPDATE exercise_library SET howto = 'Rückenlage, Füße aufgestellt, Knie 90°. Hüfte heben bis Oberkörper und Oberschenkel eine Linie bilden. Gesäß oben 2 s anspannen. Kontrolliert senken.' WHERE name = 'Glute Bridge' AND howto IS NULL;

UPDATE exercise_library SET howto = 'Rücken flach an Wand, Beine in 90° Winkel. Oberschenkel parallel zum Boden. Halten. Kein Abstützen auf Oberschenkeln. Gleichmäßig atmen.' WHERE name = 'Wall Sit' AND howto IS NULL;

UPDATE exercise_library SET howto = 'Breite Fußstellung, Zehenspitzen nach außen (45°). Tief in die Hocke gehen, Knie über Zehenspitzen drücken. Oberkörper aufrecht. Aus den Fersen hochdrücken.' WHERE name = 'Sumo Squats' AND howto IS NULL;

UPDATE exercise_library SET howto = 'Stehend, auf Zehenspitzen hochdrücken. Oben 1 s halten, Waden maximal anspannen. Langsam senken, Fersen unter Ausgangsniveau (Stretch). An Stufe für mehr ROM.' WHERE name = 'Calf Raises' AND howto IS NULL;

UPDATE exercise_library SET howto = 'Einbeinig stehen, Oberkörper nach vorn kippen. Hinteres Bein geht gestreckt nach hinten. Rücken gerade, bis Hamstring-Stretch spürbar. Langsam zurück. Balance halten.' WHERE name = 'Single Leg Deadlift' AND howto IS NULL;

UPDATE exercise_library SET howto = 'Kurzhantel vor Körper halten. Hip Hinge: Hüfte nach hinten, Knie minimal gebeugt. Hantel nah am Körper bis Mitte Schienbein. Hamstring-Stretch spüren. Hüfte nach vorn, aufrichten.' WHERE name = 'Rumänisches Kreuzheben' AND howto IS NULL;

UPDATE exercise_library SET howto = 'Hinterer Fuß auf Bank oder Stuhl. Kurzhantel seitlich. Senkrecht nach unten senken, vorderes Knie 90°. Explosiv hochdrücken. Position näher = Quad, weiter = Glute.' WHERE name = 'Bulgarian Split Squats' AND howto IS NULL;

UPDATE exercise_library SET howto = 'Tiefe Kniebeuge, explosiv abspringen. Arme schwingen mit. Weich auf Vorfuß landen, sofort in nächste Wiederholung. Knie nicht nach innen fallen lassen.' WHERE name = 'Jump Squats' AND howto IS NULL;

UPDATE exercise_library SET howto = 'Unterarmstütz: Ellbogen unter Schultern, Körper bildet gerade Linie. Core maximal anspannen, Gesäß aktiv. Nicht durchhängen oder Pike-Position. Gleichmäßig atmen.' WHERE name = 'Plank' AND howto IS NULL;

UPDATE exercise_library SET howto = 'Liegestützposition. Abwechselnd Knie explosiv Richtung Ellbogen ziehen. Hüfte stabil halten, nicht hochkommen. Tempo steigern für Cardio-Effekt.' WHERE name = 'Mountain Climbers' AND howto IS NULL;

UPDATE exercise_library SET howto = 'Rückenlage, Hände hinter Kopf. Beine angehoben. Rechter Ellbogen zum linken Knie, dabei rechtes Bein strecken. Seite wechseln. Fließende Radfahr-Bewegung.' WHERE name = 'Bicycle Crunches' AND howto IS NULL;

UPDATE exercise_library SET howto = 'Sitzend, Oberkörper leicht zurücklehnen, Füße angehoben. Hände vor der Brust (optional KH). Oberkörper rotieren, Hände abwechselnd neben Hüfte führen. Core stabil.' WHERE name = 'Russian Twists' AND howto IS NULL;

UPDATE exercise_library SET howto = 'Rückenlage, Hände unter Gesäß oder seitlich. Gestreckte Beine langsam bis 90° anheben. Kontrolliert senken bis kurz über Boden. Unterer Rücken bleibt am Boden.' WHERE name = 'Leg Raises' AND howto IS NULL;

UPDATE exercise_library SET howto = 'Rückenlage, Arme hoch, Knie 90°. Gegengleich rechten Arm + linkes Bein strecken. Unterer Rücken fest am Boden! Zurück, Seite wechseln. Langsam, kontrolliert.' WHERE name = 'Dead Bug' AND howto IS NULL;

UPDATE exercise_library SET howto = 'Seitlage, Unterarm aufgestützt, Ellbogen unter Schulter. Hüfte heben, Körper bildet gerade Linie. 20–30 s pro Seite. Hüfte nicht absinken lassen.' WHERE name = 'Side Plank' AND howto IS NULL;

UPDATE exercise_library SET howto = 'Rückenlage, Arme über Kopf gestreckt, Beine gestreckt angehoben (15–20 cm). Unterer Rücken fest am Boden pressen. Halten. Bauchmuskeln maximal angespannt.' WHERE name = 'Hollow Body Hold' AND howto IS NULL;

UPDATE exercise_library SET howto = 'Aus dem Stand in die Hocke, Hände auf Boden. Füße nach hinten springen (Liegestützposition). Optional Push-Up. Füße zurück zur Hocke. Explosiv hochspringen.' WHERE name = 'Burpees' AND howto IS NULL;

UPDATE exercise_library SET howto = 'Vor einer stabilen Box stehen. Beidbeinig abspringen und auf der Box landen. Knie leicht gebeugt, Landung weich. Aufstehen, kontrolliert heruntersteigen. Nicht runterspringen.' WHERE name = 'Box Jumps' AND howto IS NULL;

UPDATE exercise_library SET howto = 'Seitlicher Sprung auf ein Bein. Anderes Bein schwingt hinter dem Standbein vorbei. Weich auf Vorfuß landen. Sofort zur anderen Seite springen. Wie Eisschnelllauf.' WHERE name = 'Skater Jumps' AND howto IS NULL;

UPDATE exercise_library SET howto = 'Vierfüßlerstand, Knie knapp über Boden. Vorwärtsbewegen: rechte Hand + linker Fuß, dann links + rechts. Rücken flach halten. Auch rückwärts möglich.' WHERE name = 'Bear Crawl' AND howto IS NULL;

UPDATE exercise_library SET howto = 'Hüftöffner: Aus dem Sitzen vorderes Bein 90° angewinkelt, hinteres Bein 90° nach hinten. Oberkörper aufrecht, Hüfte sinken lassen. 30–45 s pro Seite.' WHERE name = 'Pigeon Pose' AND howto IS NULL;

UPDATE exercise_library SET howto = 'Stehend oder sitzend. Beine gestreckt, Oberkörper langsam nach vorn beugen. Hände Richtung Zehen. Dehnung in der Oberschenkelrückseite spüren. 30 s halten, nicht federn.' WHERE name = 'Hamstring Stretch' AND howto IS NULL;

UPDATE exercise_library SET howto = 'Band oder Stab weit greifen. Arme gestreckt über Kopf und langsam hinter den Rücken rotieren. Bei Spannung stoppen, nicht durch Schmerz arbeiten. Schulter-Mobilität verbessern.' WHERE name = 'Shoulder Dislocates' AND howto IS NULL;

UPDATE exercise_library SET howto = 'Großer Ausfallschritt. Ellbogen zum vorderen Fuß senken. Dann Arm zur Decke öffnen (Rotation). 3–5 s halten. Kombiniert Hüft-, Brust- und Schulterdehnung.' WHERE name = 'World''s Greatest Stretch' AND howto IS NULL;
